                              <h5 className="font-medium text-gray-700 mb-2">Payment Status</h5>
                              {payment.amountPaid && (
                                <div className="space-y-1">
                                  <div className="text-sm text-gray-600">
                                    Paid: ${paid.toFixed(2)}
                                  </div>
