                                    <div className="text-sm text-red-600">
                                      Remaining: ${remaining.toFixed(2)}
                                    </div>
                                  )}
                                </div>
                              )}
                            </div>
                          </div>

                          {payment.description && (
                            <div className="mb-4">
                              <h5 className="font-medium text-gray-700 mb-2">Description</h5>
