                  <button
                    key={emoji}
                    onClick={() => addEmoji(emoji)}
                    className="text-xl hover:bg-gray-100 rounded-lg p-2 transition-colors hover:scale-110 transform"
                    title={`Add ${emoji}`}
                  >
                    {emoji}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="flex space-x-2">
            <div className="flex space-x-1">
              {/* File Upload Button */}
              <Button 
                variant="outline" 
                size="sm"
                onClick={() => fileInputRef.current?.click()}
                disabled={sendMessageMutation.isPending}
              >
                <Paperclip className="h-4 w-4" />
              </Button>

              {/* Emoji Button */}
              <Button 
                variant="outline" 
                size="sm"
                onClick={() => setShowEmojiPicker(!showEmojiPicker)}
                disabled={sendMessageMutation.isPending}
              >
                <Smile className="h-4 w-4" />
              </Button>
            </div>

            <Input
              placeholder={selectedFile ? "Add a caption..." : "Type your message..."}
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyPress={handleKeyPress}
              className="flex-1"
              disabled={sendMessageMutation.isPending}
            />

            <Button 
              onClick={handleSendMessage}
              disabled={sendMessageMutation.isPending || (!message.trim() && !selectedFile)}
              size="sm"
            >
              {sendMessageMutation.isPending ? (
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
              ) : (
                <Send className="h-4 w-4" />
              )}
            </Button>
          </div>

          {/* Hidden File Input */}
          <input
            ref={fileInputRef}
            type="file"
            hidden
            accept="image/*,.pdf,.doc,.docx,.txt"
            onChange={handleFileSelect}
          />

          <p className="text-xs text-gray-500 mt-2">
            Press Enter to send • Shift+Enter for new line • Max file size: 10MB
          </p>
        </div>
      </DialogContent>
    </Dialog>
  );
}

